import statistics
from typing import Dict, List, Union


def calcular_estatisticas(numeros: List[Union[int, float]]) -> Dict[str, float]:
    """Calcula media, mediana e desvio padrao populacional."""
    if not numeros:
        raise ValueError("A lista nao pode estar vazia.")

    return {
        "media": statistics.mean(numeros),
        "mediana": statistics.median(numeros),
        "desvio_padrao": statistics.pstdev(numeros),
    }
